#!/usr/bin/env bash
python3 - <<'PYEOF'
import sys
sys.path.insert(0, "src")
try:
    from duration import parse_duration as p
except Exception as e:
    print("import failed:", e); sys.exit(1)
ok = True
valid = [("90s",90),("1h30m",5400),("2d4h",187200),("45m10s",2710),("1d",86400),
         ("1h 30m",5400),("1H30M",5400),("0s",0),("10m",600),("3600s",3600),
         ("2d 4h 30m",189000),("15s",15),("1m",60)]
invalid = ["","abc","10","h","10x","1h30","-5s","1.5h","s10","10 20s","m"]
for inp,exp in valid:
    try:
        got = p(inp)
        if got != exp: print(f"FAIL valid {inp!r}: got {got!r} want {exp}"); ok=False
    except Exception as e:
        print(f"FAIL valid {inp!r}: raised {type(e).__name__}"); ok=False
for inp in invalid:
    try:
        got = p(inp); print(f"FAIL invalid {inp!r}: expected ValueError got {got!r}"); ok=False
    except ValueError:
        pass
    except Exception as e:
        print(f"FAIL invalid {inp!r}: expected ValueError got {type(e).__name__}"); ok=False
sys.exit(0 if ok else 1)
PYEOF
